module RefModule(
    q,
    clk,
    d,
    reset_b
);output q;
    input clk;
    input d;
    input reset_b;

    reg q;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge reset_b or posedge dbg_halt) begin
        if (~reset_b) begin
            q <= 1'b0;
        end else begin
            q <= d;
        end
    end

endmodule
